using System.IO;
using System.Linq;
using System.Threading.Tasks;

public sealed class ResumableBenchmarkRunner
{
    private readonly ConcurrentDictionary<string, BenchmarkResult> _results;
    private readonly string _checkpointPath;
    private readonly object _lock = new();

    public ResumableBenchmarkRunner(string checkpointPath)
    {
        _checkpointPath = checkpointPath;
        _results = LoadCheckpoints();
    }

    public async Task<BenchmarkResult> RunAsync(BenchmarkContext context, CancellationToken ct = default)
    {
        var key = GetKey(context);

        // Resume if already completed
        if (_results.TryGetValue(key, out var cached))
            return cached;

        // Serialize and run one at a time (Docker constraint)
        lock (_lock)
        {
            // Double-check under lock
            if (_results.TryGetValue(key, out cached))
                return cached;

            var result = await RunBenchmarkAsync(context, ct);
            _results[key] = result;
            SaveCheckpoint(key, result);
            return result;
        }
    }

    public IEnumerable<BenchmarkResult> GetAllResults() => _results.Values;

